def solve(points: Array[Array[Long]]): Long = {
  val MOD = 1000000007L
  val yMap = points.groupBy(p => p(1)).mapValues(_.size)
  val totalSum = yMap.values.map(m => {
    val c = m * (m - 1) / 2
    c % MOD
  }).sum % MOD
  val sumSquares = yMap.values.map(m => {
    val c = m * (m - 1) / 2
    (c * c) % MOD
  }).sum % MOD
  val totalSumSquared = (totalSum * totalSum) % MOD
  val numerator = (totalSumSquared - sumSquares) % MOD
  val inv2 = (MOD + 1) / 2
  (numerator * inv2) % MOD
}
